INSERT INTO `ayudas_emociones` (`id`, `es_titulo`, `es_descripcion`, `en_titulo`, `en_descripcion`, `fecha_r`) VALUES
(1, 'Hacer 20 cosas a la vez', 'Podemos hacer hasta 30 cosas a la vez mientras tengamos esa capacidad de ejecutarlas sin terminar con dolor de cabeza, cuello, espalda, estómago o agotamiento al final de la tarde por descuidar nuestra rutina de mantenimiento corporal', 'Hacer 20 cosas a la vez', 'Podemos hacer hasta 30 cosas a la vez mientras tengamos esa capacidad de ejecutarlas sin terminar con dolor de cabeza, cuello, espalda, estómago o agotamiento al final de la tarde por descuidar nuestra rutina de mantenimiento corporal', '2024-08-07 17:48:57'),
(2, 'Nada es perfecto', 'Entender que nada es perfecto ni en todo se puede ser flexible. Permite soluciones satisfactorias sin gasto de energía vital para la vida', 'Nada es perfecto', 'Entender que nada es perfecto ni en todo se puede ser flexible. Permite soluciones satisfactorias sin gasto de energía vital para la vida', '2024-08-07 17:49:19'),
(3, 'Ocuparse sin preocuparse', 'Esto implica tener mente fría de observar el evento para que la ejecución sea elegante y precisa sin estar pendiente del resultado para evitar la ansiedad', 'Ocuparse sin preocuparse', 'Esto implica tener mente fría de observar el evento para que la ejecución sea elegante y precisa sin estar pendiente del resultado para evitar la ansiedad', '2024-08-07 17:49:37'),
(4, 'Todo rápido', 'Entender que nada puede ser rápido o lento a través de un discernimiento inteligente permite que esto proceso sea agradable y creativo, lo cual favorece el que su máquina corporal esté en óptimas condiciones de salud', 'Todo rápido', 'Entender que nada puede ser rápido o lento a través de un discernimiento inteligente permite que esto proceso sea agradable y creativo, lo cual favorece el que su máquina corporal esté en óptimas condiciones de salud', '2024-08-07 17:49:59'),
(5, 'Aprenda a decir no o si', 'De forma inteligente para que logre objetivos que le permitan avanzar en sus propósitos sin generar emociones conflictivas', 'Aprenda a decir no o si', 'De forma inteligente para que logre objetivos que le permitan avanzar en sus propósitos sin generar emociones conflictivas', '2024-08-07 17:50:25'),
(6, 'Relación de pareja', 'Este es un proceso donde el respeto al espacio de cada quien es fundamental para que esta relación prosiga amigablemente. Toda vez que se presente un conflicto, se debe analizar el factor que se debe corregir o mejorar si se desea continuar en ese estado', 'Relación de pareja', 'Este es un proceso donde el respeto al espacio de cada quien es fundamental para que esta relación prosiga amigablemente. Toda vez que se presente un conflicto, se debe analizar el factor que se debe corregir o mejorar si se desea continuar en ese estado', '2024-08-07 17:50:47'),
(7, 'Relación con los hijos', 'Debemos ser consecuentes con el diálogo para que este proceso sea agradable y beneficioso a las partes, asesorándonos con una experta en manejo de adolescentes si fuera el caso', 'Relación con los hijos', 'Debemos ser consecuentes con el diálogo para que este proceso sea agradable y beneficioso a las partes, asesorándonos con una experta en manejo de adolescentes si fuera el caso', '2024-08-07 17:51:03'),
(8, 'Relación con la familia', 'Es bueno cultivar siempre que exista reciprocidad para que el proceso sea equilibrado', 'Relación con la familia', 'Es bueno cultivar siempre que exista reciprocidad para que el proceso sea equilibrado', '2024-08-07 17:51:20'),
(9, 'Relación en el trabajo', 'Lo esencial es que nos guste y tenga una remuneración acorde con nuestra responsabilidad en ese proceso o a futuro, si nos esforzamos logremos ese objetivo', 'Relación en el trabajo', 'Lo esencial es que nos guste y tenga una remuneración acorde con nuestra responsabilidad en ese proceso o a futuro, si nos esforzamos logremos ese objetivo', '2024-08-07 17:51:35'),
(10, 'Relación con nuestro medio ambiente o hábitat', 'Mientras exista la posibilidad de mejorar a futuro, debe ser posible adaptarse a este ambiente de forma optimista si no es así salga corriendo de ese ambiente', 'Relación con nuestro medio ambiente o hábitat', 'Mientras exista la posibilidad de mejorar a futuro, debe ser posible adaptarse a este ambiente de forma optimista si no es así salga corriendo de ese ambiente', '2024-08-07 17:51:53');
