(4, 1, 186, 'Gris: No hay ese síntoma\nVerde obscuro: síntoma muy leve\nVerde claro: Síntoma leve\nAmarillo: Síntoma moderado\nAnaranjado: Síntoma Intenso\nRojo: Síntoma muy intenso\n', 1, NULL, '2022-05-08 00:00:00'),
(5, 1, 194, 'Verde obscuro: Muy leve daño\nVerde claro: Leve daño\nAmarillo: Daño moderado \nAnaranjado: Daño  severo\nRojo: Daño muy severo ', 1, NULL, '2022-05-08 00:00:00'),
(6, 1, 251, 'Rojo: En 1 mes \nAnaranjado:En 3 meses\nAmarillo: En 6  meses\nVerde claro: En 12 meses\nVerde obscuro:bEn 24 meses', 1, NULL, '2022-05-08 00:00:00'),
